import { NextRequest, NextResponse } from "next/server";

export async function POST(req: NextRequest) {
    try {
        const { message } = await req.json();

        if (!message) {
            return NextResponse.json({ reply: "No message provided." }, { status: 400 });
        }

        if (!process.env.GROQ_API_KEY) {
            console.error("❌ GROQ_API_KEY is not set!");
            return NextResponse.json(
                { reply: "API key not configured on server." },
                { status: 500 }
            );
        }

        const response = await fetch("https://api.groq.com/openai/v1/chat/completions", {
            method: "POST",
            headers: {
                "Content-Type": "application/json",
                Authorization: `Bearer ${process.env.GROQ_API_KEY}`,
            },
            body: JSON.stringify({
                model: "llama-3.1-8b-instant",
                messages: [{ role: "user", content: message }],
            }),
        });

        const data = await response.json();

        if (data.error) {
            console.error("Groq API error:", data.error);
            return NextResponse.json(
                { reply: `Groq error: ${data.error.message}` },
                { status: 502 }
            );
        }

        const reply = data.choices?.[0]?.message?.content || "No response from Groq";
        return NextResponse.json({ reply });
    } catch (err: unknown) {
        const message = err instanceof Error ? err.message : "Unknown error";
        console.error("Server error:", err);
        return NextResponse.json({ reply: "Backend AI error: " + message }, { status: 500 });
    }
}
